// Flatten Teams messages into clean objects, ignoring system messages
let result = [];

for (const item of items) {
  const messages = item.json.value || [];

  for (const msg of messages) {
    // Get content safely
    let content = msg.body?.content || null;

    // Skip trash/system messages
    if (!content || content.trim() === "<systemEventMessage/>") {
      continue;
    }

    let entry = {
      teamId: msg.channelIdentity?.teamId || msg.eventDetail?.teamId || null,
      channelId: msg.channelIdentity?.channelId || msg.eventDetail?.channelId || null,
      displayName: msg.from?.user?.displayName || msg.eventDetail?.channelDisplayName || null,
      content: content,
      createdDateTime: msg.createdDateTime || null,
      lastModifiedDateTime: msg.lastModifiedDateTime || null,
    };

    result.push({ json: entry });
  }
}

return result;

