const allChannels = [];

items.forEach(item => {
  const data = item.json;

  // Extract teamId using regex
  const context = data["@odata.context"] || "";
  const match = context.match(/teams\('([^']+)'\)/);
  const teamId = match ? match[1] : null;

  // Collect all channels
  (data.value || []).forEach(channel => {
    allChannels.push({
      channelId: channel.id || null,
      displayName: channel.displayName || null,
      teamId,
    });
  });
});

// Return as a single item with a list
return [
  {
    json: {
      channels: allChannels
    }
  }
];

// Get the array under $json.value
