// Get the input from the AI Agent node
const agentOutput = $input.first().json.output;

let data;

// Use a regular expression to extract the JSON array string, which starts with '[' and ends with ']'
const jsonMatch = agentOutput.match(/\[[\s\S]*\]/);

if (jsonMatch) {
  try {
    // If a JSON array-like string is found, parse it
    const jsonString = jsonMatch[0];
    data = JSON.parse(jsonString);
  } catch (e) {
    // Log the error for debugging if parsing fails
    console.error("Failed to parse JSON array:", e.message);

    // Fallback if parsing fails, return an error object for easier debugging
    data = { 
      error: "Failed to parse JSON from AI output.", 
      rawOutput: agentOutput 
    };
  }
} else {
  // If no JSON array is found, assume it's a plain text answer or an error
  // This handles cases where the AI might respond with something other than the expected array.
  data = { 
    answer: agentOutput 
  };
}

// Always return an object as the value of the 'json' property
let output;
if (Array.isArray(data)) {
  output = { result: data };
} else {
  output = data;
}
return [{ json: output }];

// 1. Get the single output item from the 'Code17' node.
const code17output = $('Code17').first();

// 2. Access the nested 'result' array from within that item's JSON.
// This is the key change to fix the issue.
const itemsToMatch = code17output.json.result || [];

// 3. Create a simple list of just the team IDs from the items in the 'result' array.
const idsToMatch = itemsToMatch.map(item => item.teamId);

// 4. Get the complete list of all available teams from this node's direct input.
const allTeamsList = $input.first().json.value || [];

// 5. Use .filter() to find every team in the main list whose ID exists in your idsToMatch list.
const matchedTeams = allTeamsList.filter(team => idsToMatch.includes(team.id));

// 6. Format the list of found teams into the correct output structure.
return matchedTeams.map(team => ({
  json: {
    teamId: team.id,
    teamName: team.displayName
  }
}));

// 1. Get all of your data sources
const allTasks = $('Code17').first().json.result || [];
const allTeamsWithNames = $('Code18').all(); // From the node that matched team IDs to names
const allChannelLists = $('get channel6').all(); // From the HTTP request node

// 2. Build a Team Name Directory for fast lookups
// Key: teamId, Value: teamName
const teamMap = new Map();
for (const teamItem of allTeamsWithNames) {
  teamMap.set(teamItem.json.teamId, teamItem.json.teamName);
}

// 3. Build a Channel Directory that also includes the tenantId
// Key: channelId, Value: { displayName, tenantId }
const channelMap = new Map();
for (const channelListItem of allChannelLists) {
  const channels = channelListItem.json.value || [];
  for (const channel of channels) {
    if (channel) { // Ensure channel is not null
      channelMap.set(channel.id, {
        displayName: channel.displayName,
        tenantId: channel.tenantId
      });
    }
  }
}

// 4. Process each original task to enrich it with all required data
const finalResults = allTasks.map(task => {
  const teamName = teamMap.get(task.teamId) || null;
  const matchedChannel = channelMap.get(task.channelId);

  const channelName = matchedChannel ? matchedChannel.displayName : null;
  const tenantId = matchedChannel ? matchedChannel.tenantId : null;

  // 5. Construct the deep link URL right here in the code
  let deepLinkUrl = null;
  if (channelName && task.channelId && task.teamId && tenantId) {
    // We use encodeURIComponent to safely handle special characters in channel names
    deepLinkUrl = `https://teams.microsoft.com/l/channel/${encodeURIComponent(task.channelId)}/${encodeURIComponent(channelName)}?groupId=${task.teamId}&tenantId=${tenantId}`;
  }

  // 6. Return a single, complete object with everything you need
  return {
    answer: task.answer,
    user: task.displayName,
    createdDate: task.createdDateTime,
    teamName: teamName,
    channelName: channelName,
    deepLinkUrl: deepLinkUrl
  };
});

return [{
  json: {
    results: finalResults
  }
}];

// Get the array of results from the single input item
const results = $input.first().json.result;

// Check if the result array exists but is empty
if (results && results.length === 0) {
  // If it's empty, return a single item with a custom message
  return [{ json: { message: "item not found" } }];
}

// If the array has items, process them as before
if (results) {
  return results.map(item => ({ json: item }));
}

// If the 'result' key doesn't exist at all, return nothing
return [];
